**C++ 質數篩模板**：

```cpp
// 埃氏篩：篩出 [2, n] 的所有質數
vector<int> sieve(int n) {
    vector<int> primes;
    vector<bool> is_prime(n + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (int p = 2; p <= n; ++p) {
        if (is_prime[p]) {
            primes.push_back(p);
            for (long long i = (long long)p * p; i <= n; i += p) { // 從 p² 開始篩 {
                is_prime[i] = false;
            }
            }
        }
    }
    return primes;
}
```
